@* Displays a single task card with move buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <span class="badge bg-@PriorityClass me-1">@Task.Priority</span>
        <span class="small text-muted">@Task.DueDate.ToString("MMM dd")</span>
        <div class="mt-2 d-flex gap-1">
            @if (ShowMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveLeft" disabled="@IsMoving">
                    &larr; Move Left
                </button>
            }
            @if (ShowMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveRight" disabled="@IsMoving">
                    Move Right &rarr;
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback OnMoveLeft { get; set; }
    [Parameter] public EventCallback OnMoveRight { get; set; }
    [Parameter] public bool IsMoving { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "danger",
        "Medium" => "warning",
        _ => "success"
    };
}

@* Inline form to create a new task within a column *@

@if (!IsVisible)
{
    <button class="btn btn-outline-primary btn-sm w-100" @onclick="Show">+ Add Task</button>
}
else
{
    <div class="card mt-2">
        <div class="card-body p-2">
            <div class="mb-2">
                <input class="form-control form-control-sm" placeholder="Title" @bind="title" />
            </div>
            <div class="mb-2">
                <input class="form-control form-control-sm" placeholder="Assignee" @bind="assignee" />
            </div>
            <div class="mb-2">
                <select class="form-select form-select-sm" @bind="priority">
                    <option value="High">High</option>
                    <option value="Medium">Medium</option>
                    <option value="Low">Low</option>
                </select>
            </div>
            <div class="mb-2">
                <input type="date" class="form-control form-control-sm" @bind="dueDate" />
            </div>
            <div class="d-flex gap-1">
                <button class="btn btn-primary btn-sm" @onclick="Save" disabled="@isSaving">Save</button>
                <button class="btn btn-secondary btn-sm" @onclick="Cancel" disabled="@isSaving">Cancel</button>
            </div>
            @if (!string.IsNullOrEmpty(error))
            {
                <div class="text-danger small mt-1">@error</div>
            }
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnTaskCreated { get; set; }

    private bool IsVisible;
    private string title = "";
    private string assignee = "";
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;
    private string? error;

    private void Show() => IsVisible = true;

    private void Cancel()
    {
        ResetForm();
        IsVisible = false;
    }

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(title))
        {
            error = "Title is required.";
            return;
        }

        error = null;
        isSaving = true;
        try
        {
            await OnTaskCreated.InvokeAsync((title.Trim(), assignee.Trim(), priority, dueDate));
            ResetForm();
            IsVisible = false;
        }
        catch (Exception ex)
        {
            error = ex.Message;
        }
        finally
        {
            isSaving = false;
        }
    }

    private void ResetForm()
    {
        title = "";
        assignee = "";
        priority = "Medium";
        dueDate = DateTime.Today.AddDays(7);
        error = null;
    }
}

@* Summary statistics bar for the Kanban board *@

<div class="d-flex flex-wrap gap-3 mb-3 p-3 bg-light rounded">
    <div><strong>Total:</strong> @Tasks.Count</div>
    <div><strong>To Do:</strong> @Tasks.Count(t => t.Status == "To Do")</div>
    <div><strong>In Progress:</strong> @Tasks.Count(t => t.Status == "In Progress")</div>
    <div><strong>Done:</strong> @Tasks.Count(t => t.Status == "Done")</div>
    <div class="@(OverdueCount > 0 ? "text-danger" : "")">
        <strong>Overdue:</strong> @OverdueCount
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();

    private int OverdueCount => Tasks.Count(t => t.DueDate < DateTime.Today && t.Status != "Done");
}

@* Search bar that filters tasks by title *@

<div class="mb-3">
    <input class="form-control" placeholder="Search tasks by title..." @oninput="OnInput" value="@SearchTerm" />
</div>

@code {
    [Parameter] public string SearchTerm { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> OnSearchChanged { get; set; }

    private async Task OnInput(ChangeEventArgs e)
    {
        await OnSearchChanged.InvokeAsync(e.Value?.ToString() ?? "");
    }
}

@* A single Kanban column: header, task cards, and add-task form *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@ColumnName</strong>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body p-2" style="overflow-y:auto; max-height:70vh;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="ColumnIndex > 0"
                          ShowMoveRight="ColumnIndex < 2"
                          IsMoving="movingTaskId == task.Id"
                          OnMoveLeft="() => MoveLeft(task)"
                          OnMoveRight="() => MoveRight(task)" />
            }
            <AddTaskForm OnTaskCreated="HandleTaskCreated" />
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = "";
    [Parameter, EditorRequired] public int ColumnIndex { get; set; }
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<(int TaskId, string NewStatus)> OnTaskMoved { get; set; }
    [Parameter, EditorRequired] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate, string Status)> OnTaskAdded { get; set; }

    private static readonly string[] Statuses = ["To Do", "In Progress", "Done"];
    private int? movingTaskId;

    private async Task MoveLeft(TaskItem task)
    {
        if (ColumnIndex <= 0) return;
        movingTaskId = task.Id;
        await OnTaskMoved.InvokeAsync((task.Id, Statuses[ColumnIndex - 1]));
        movingTaskId = null;
    }

    private async Task MoveRight(TaskItem task)
    {
        if (ColumnIndex >= 2) return;
        movingTaskId = task.Id;
        await OnTaskMoved.InvokeAsync((task.Id, Statuses[ColumnIndex + 1]));
        movingTaskId = null;
    }

    private async Task HandleTaskCreated((string Title, string Assignee, string Priority, DateTime DueDate) args)
    {
        await OnTaskAdded.InvokeAsync((args.Title, args.Assignee, args.Priority, args.DueDate, ColumnName));
    }
}

@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="text-center p-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
        <p class="mt-2">Loading tasks...</p>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardSummaryBar Tasks="allTasks" />
    <BoardSearchBar SearchTerm="@searchTerm" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        @for (var i = 0; i < columns.Length; i++)
        {
            var index = i;
            <KanbanColumn ColumnName="@columns[index]"
                          ColumnIndex="index"
                          Tasks="GetFilteredTasks(columns[index])"
                          OnTaskMoved="HandleTaskMoved"
                          OnTaskAdded="HandleTaskAdded" />
        }
    </div>
}

@code {
    private static readonly string[] columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> allTasks = new();
    private string searchTerm = "";
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void HandleSearchChanged(string term)
    {
        searchTerm = term;
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));
        }
        return tasks.ToList();
    }

    private async Task HandleTaskMoved((int TaskId, string NewStatus) args)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(args.TaskId, args.NewStatus);
            var task = allTasks.FirstOrDefault(t => t.Id == args.TaskId);
            if (task is not null)
            {
                allTasks = allTasks.Select(t => t.Id == args.TaskId ? t with { Status = args.NewStatus } : t).ToList();
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleTaskAdded((string Title, string Assignee, string Priority, DateTime DueDate, string Status) args)
    {
        var newTask = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
        // CreateTaskAsync returns the task with default status; override with the column's status
        var taskWithStatus = newTask with { Status = args.Status };
        if (args.Status != newTask.Status)
        {
            await TaskService.UpdateTaskStatusAsync(taskWithStatus.Id, args.Status);
        }
        allTasks.Add(taskWithStatus);
    }
}

