@* A single Kanban column: header, task cards, and add-task form *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>@ColumnName</strong>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body p-2" style="overflow-y:auto; max-height:70vh;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="ColumnIndex > 0"
                          ShowMoveRight="ColumnIndex < 2"
                          IsMoving="movingTaskId == task.Id"
                          OnMoveLeft="() => MoveLeft(task)"
                          OnMoveRight="() => MoveRight(task)" />
            }
            <AddTaskForm OnTaskCreated="HandleTaskCreated" />
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = "";
    [Parameter, EditorRequired] public int ColumnIndex { get; set; }
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<(int TaskId, string NewStatus)> OnTaskMoved { get; set; }
    [Parameter, EditorRequired] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate, string Status)> OnTaskAdded { get; set; }

    private static readonly string[] Statuses = ["To Do", "In Progress", "Done"];
    private int? movingTaskId;

    private async Task MoveLeft(TaskItem task)
    {
        if (ColumnIndex <= 0) return;
        movingTaskId = task.Id;
        await OnTaskMoved.InvokeAsync((task.Id, Statuses[ColumnIndex - 1]));
        movingTaskId = null;
    }

    private async Task MoveRight(TaskItem task)
    {
        if (ColumnIndex >= 2) return;
        movingTaskId = task.Id;
        await OnTaskMoved.InvokeAsync((task.Id, Statuses[ColumnIndex + 1]));
        movingTaskId = null;
    }

    private async Task HandleTaskCreated((string Title, string Assignee, string Priority, DateTime DueDate) args)
    {
        await OnTaskAdded.InvokeAsync((args.Title, args.Assignee, args.Priority, args.DueDate, ColumnName));
    }
}

