toolArgs.file_text:
@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="text-center p-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
        <p class="mt-2">Loading tasks...</p>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardSummaryBar Tasks="allTasks" />
    <BoardSearchBar SearchTerm="@searchTerm" OnSearchChanged="HandleSearchChanged" />

    <div class="row g-3">
        @for (var i = 0; i < columns.Length; i++)
        {
            var index = i;
            <KanbanColumn ColumnName="@columns[index]"
                          ColumnIndex="index"
                          Tasks="GetFilteredTasks(columns[index])"
                          OnTaskMoved="HandleTaskMoved"
                          OnTaskAdded="HandleTaskAdded" />
        }
    </div>
}

@code {
    private static readonly string[] columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> allTasks = new();
    private string searchTerm = "";
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void HandleSearchChanged(string term)
    {
        searchTerm = term;
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));
        }
        return tasks.ToList();
    }

    private async Task HandleTaskMoved((int TaskId, string NewStatus) args)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(args.TaskId, args.NewStatus);
            var task = allTasks.FirstOrDefault(t => t.Id == args.TaskId);
            if (task is not null)
            {
                allTasks = allTasks.Select(t => t.Id == args.TaskId ? t with { Status = args.NewStatus } : t).ToList();
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task HandleTaskAdded((string Title, string Assignee, string Priority, DateTime DueDate, string Status) args)
    {
        var newTask = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
        // CreateTaskAsync returns the task with default status; override with the column's status
        var taskWithStatus = newTask with { Status = args.Status };
        if (args.Status != newTask.Status)
        {
            await TaskService.UpdateTaskStatusAsync(taskWithStatus.Id, args.Status);
        }
        allTasks.Add(taskWithStatus);
    }
}

