+                allTasks = allTasks.Select(t => t.Id == args.TaskId ? t with { Status = args.NewStatus } : t).ToList();
+            }
+        }
+        catch (Exception ex)
+        {
+            errorMessage = ex.Message;
+        }
+    }
+
+    private async Task HandleTaskAdded((string Title, string Assignee, string Priority, DateTime DueDate, string Status) args)
+    {
+        var newTask = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
+        // CreateTaskAsync returns the task with default status; override with the column's status
+        var taskWithStatus = newTask with { Status = args.Status };
+        if (args.Status != newTask.Status)
+        {
+            await TaskService.UpdateTaskStatusAsync(taskWithStatus.Id, args.Status);
+        }
+        allTasks.Add(taskWithStatus);
+    }
+}
